import BcomComponent from "../common/component";

BcomComponent({
    // options: {
    //     virtualHost: true
    // },
    props: {
        show: {
            type: Boolean,
            value: false,
            observer(val)  {
                if(!val) return;
                this.initData(this.data.color || "#ff0000");
            }
        },
        color: {
            type: String,
            value: ''
        },
        commonColor: {
            type: String,
            value: "#000000,#ffffff,#ff0000,#ffa500,#00ff00,#0000ff,#ff00ff,#00ffff,#ffff00,#70db93,#cccccc,#999999"
        },
        comfirmText: {
            type: String,
            value: "确定"
        },
        cancelText: {
            type: String,
            value: "取消"
        },
        title: {
            type: String,
            value: "请选择"
        }
    },
    data: {
        colorHex: "#ff0000",
        colorRgb: {r: 255, g: 0, b: 0},
        colorHsv: {h: 0, s: 100, v: 100},
        selectColorList: []
    },
    created() {
        this.set({
            selectColorList: this.data.commonColor.toLocaleLowerCase().split(",")
        });
    },
    mounted() {
        // this.initData(this.data.color || "#ff0000");
    },
    methods: {
        async chooseColor(e) {
            if(this.hasClick()) return;
            const colorHex = e.currentTarget.dataset.color;
            this.initData(colorHex);
        },
        initData(color) {
            let colorHex = this.data.colorHex;
            let colorRgb = this.data.colorRgb;
            let colorHsv = this.data.colorHsv;
            let lowColor = color.toLocaleLowerCase();
            if(lowColor.indexOf("rgb") !== -1) {
                const rgbMatch = lowColor.match(/\((.*?)\)/);
                if (rgbMatch && rgbMatch.length > 1) {
                    let rgbs = rgbMatch[1].split(",");
                    colorRgb = {r: Number(rgbs[0].trim()), g: Number(rgbs[1].trim()), b: Number(rgbs[2].trim())}
                    colorHsv = this.rgbToHsv(colorRgb.r, colorRgb.g, colorRgb.b);
                    colorHex = this.rgbToHex(colorRgb.r, colorRgb.g, colorRgb.b);
                }
            } else {
                colorHex = lowColor;
                colorRgb = this.hexToRgb(lowColor);
                colorHsv = this.hexToHsv(lowColor);
            }
            this.set({
                colorHex, colorRgb, colorHsv
            });
            this.createSelectorQuery().in(this)
                .select('.color-picker-target')
                .boundingClientRect()
                .exec((res) => {
                    const rect = res[0];
                    if (rect) {
                        let hueColor = this.hsvToRgb(colorHsv.h ,100, 100);
                        this.SV = {
                            W: rect.width - 14, // block-size=14
                            H: rect.height - 14,
                            Step: (rect.width - 14) / 100
                        }
                        // 初始化定位
                        this.set({
                            hueColor: hueColor,
                            x: Math.round(colorHsv.s * this.SV.Step),
                            y: Math.round((100 - colorHsv.v) * this.SV.Step)
                        });
                    }
                });
        },
        hexToRgb(hex) {
            // 移除前缀#符号
            hex = hex.replace(/^\s*#|\s*$/g, '');
         
            // 将三位十六进制转为六位
            if (hex.length === 3) {
                hex = hex.replace(/(.)/g, '$1$1');
            }
         
            // 提取R、G、B各自的十六进制表示方式
            var rgb = /^(\w{2})(\w{2})(\w{2})$/.exec(hex);
          
            // 转为10进制并返回
            return rgb ? {
                r: parseInt(rgb[1], 16),
                g: parseInt(rgb[2], 16),
                b: parseInt(rgb[3], 16)
            } : null;
        },
        hexToHsv(hex) {
            // 将十六进制颜色转换为RGB
            let r = parseInt(hex.substring(1, 3), 16);
            let g = parseInt(hex.substring(3, 5), 16);
            let b = parseInt(hex.substring(5, 7), 16);
            return this.rgbToHsv(r, g, b);
        },
        rgbToHex(r, g, b) {
            const toHex = (num) => {
              const hex = num.toString(16);
              return hex.length == 1 ? "0" + hex : hex;
            };
            return "#" + toHex(r) + toHex(g) + toHex(b);
        },
        rgbToHsv(r, g, b) {
            let hsv_red = r / 255,
            hsv_green = g / 255,
            hsv_blue = b / 255;
            let hsv_max = Math.max(hsv_red, hsv_green, hsv_blue),
                hsv_min = Math.min(hsv_red, hsv_green, hsv_blue);
            let hsv_h, hsv_s, hsv_v = hsv_max;

            let hsv_d = hsv_max - hsv_min;
            hsv_s = hsv_max == 0 ? 0 : hsv_d / hsv_max;

            if (hsv_max == hsv_min) hsv_h = 0;
            else {
                switch (hsv_max) {
                    case hsv_red:
                        hsv_h = (hsv_green - hsv_blue) / hsv_d + (hsv_green < hsv_blue ? 6 : 0);
                        break;
                    case hsv_green:
                        hsv_h = (hsv_blue - hsv_red) / hsv_d + 2;
                        break;
                    case hsv_blue:
                        hsv_h = (hsv_red - hsv_green) / hsv_d + 4;
                        break;
                }
                hsv_h /= 6;
            }
            return {
                h: Number((hsv_h * 360).toFixed()),
                s: Number((hsv_s * 100).toFixed()),
                v: Number((hsv_v * 100).toFixed())
            }
        },
        hsvToRgb(h, s, v) {
            let hsv_h = (h / 360).toFixed(2);
            let hsv_s = (s / 100).toFixed(2);
            let hsv_v = (v / 100).toFixed(2);

            var i = Math.floor(hsv_h * 6);
            var f = hsv_h * 6 - i;
            var p = hsv_v * (1 - hsv_s);
            var q = hsv_v * (1 - f * hsv_s);
            var t = hsv_v * (1 - (1 - f) * hsv_s);

            var rgb_r = 0,
                rgb_g = 0,
                rgb_b = 0;
            switch (i % 6) {
                case 0:
                    rgb_r = hsv_v;
                    rgb_g = t;
                    rgb_b = p;
                    break;
                case 1:
                    rgb_r = q;
                    rgb_g = hsv_v;
                    rgb_b = p;
                    break;
                case 2:
                    rgb_r = p;
                    rgb_g = hsv_v;
                    rgb_b = t;
                    break;
                case 3:
                    rgb_r = p;
                    rgb_g = q;
                    rgb_b = hsv_v;
                    break;
                case 4:
                    rgb_r = t;
                    rgb_g = p;
                    rgb_b = hsv_v;
                    break;
                case 5:
                    rgb_r = hsv_v, rgb_g = p, rgb_b = q;
                    break;
            }
            return {
                r: Math.floor(rgb_r * 255),
                g: Math.floor(rgb_g * 255),
                b: Math.floor(rgb_b * 255)
            };
        },
        hsvToHex(h, s, v) {
            let rgbObj = this.hsvToRgb(h, s, v);
            return this.rgbToHex(rgbObj.r, rgbObj.g, rgbObj.b);
        },
        areaTap(res) {
            if(this.hasClick()) return;
            this.createSelectorQuery().in(this)
            .select('.color-picker-target')
            .boundingClientRect()
            .exec((r) => {
                const rect = r[0];
                if (rect) {
                    // 修正浮标位置, 魔法数字`-14`：去除半个浮标的宽度
                    let x = res.detail.x - rect.left - 7;
                    let y = res.detail.y - rect.top - 7;
                    // debugger;
                    
                    this.set({
                        x: x,
                        y: y
                    });
                    this.changeSV({
                        detail: {
                            x: x,
                            y: y
                        }
                    });
                }
            })
        },
        changeHue(e) {
            let hue = e.detail.value;
            this.setData({
                "colorHsv.h": hue,
                hueColor: this.hsvToRgb(hue, 100, 100),
                colorHex: this.hsvToHex(hue, this.data.colorHsv.s, this.data.colorHsv.v),
                colorRgb: this.hsvToRgb(hue, this.data.colorHsv.s, this.data.colorHsv.v)
            });
        },
        changeSV(e) {
            let {
                x,
                y
            } = e.detail;
            x = Math.round(x / this.SV.Step);
            y = 100 - Math.round(y / this.SV.Step);
            if(x > 100) {
                x = 100;
            }
            if(x < 0) {
                x = 0;
            }
            if(y > 100) {
                y = 100;
            }
            if(y < 0) {
                y = 0;
            }
            this.set({
                "colorHsv.s": x,
                "colorHsv.v": y,
                colorHex: this.hsvToHex(this.data.colorHsv.h, x, y),
                colorRgb: this.hsvToRgb(this.data.colorHsv.h, x, y)
            });
        },
        confirmTap() {
            if(this.hasClick()) return;
            const {
                colorHex,
                colorRgb,
                colorHsv
            } = this.data;
            const rgbText = `rgb(${colorRgb.r}, ${colorRgb.g}, ${colorRgb.b})`;
            this.$emit("confirm", {hex: colorHex, rgb: rgbText, hsv: colorHsv});
        },
        cancelTap() {
            if(this.hasClick()) return;
            this.$emit("cancel");
        },
        maskTap() {
            if(this.hasClick()) return;
            this.$emit("mask");
        }
    }
})